import asyncio


async def fetch_all_users(user_ids: list[int]) -> list[dict]:
    tasks = [fetch_user(uid) for uid in user_ids]
    return await asyncio.gather(*tasks)


# FastAPI: aggregate multiple data sources concurrently
@app.get("/aggregate")
async def get_aggregate():
    users, products, orders = await asyncio.gather(
        fetch_users(), fetch_products(), fetch_orders()
    )
    return {"users": users, "products": products, "orders": orders}

async def fetch_with_limit(urls: list[str], max_concurrent: int = 5) -> list[dict]: semaphore = asyncio.Semaphore(max_concurrent)
async def fetch_one(url: str) -> dict: async with semaphore: async with aiohttp.ClientSession() as session: async with session.get(url) as response: return await response.json()
return await asyncio.gather(*[fetch_one(url) for url in urls])
